using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ApiTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ApiTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool, Description("Get a post by its numeric ID.")]
    public async Task<string> GetPost(
        [Description("The post ID (1-100).")] int id,
        CancellationToken cancellationToken = default)
    {
        using var client = _httpClientFactory.CreateClient("api");
        var post = await client.GetFromJsonAsync<JsonElement>(
            $"/posts/{id}", cancellationToken);
        return post.ToString();
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter posts to this user ID.")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        using var client = _httpClientFactory.CreateClient("api");
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        var posts = await client.GetFromJsonAsync<JsonElement>(
            url, cancellationToken);
        return posts.ToString();
    }

    [McpServerTool, Description("Create a new post.")]
    public async Task<string> CreatePost(
        [Description("Author user ID.")] int userId,
        [Description("Post title.")] string title,
        [Description("Post body text.")] string body,
        CancellationToken cancellationToken = default)
    {
        using var client = _httpClientFactory.CreateClient("api");
        var response = await client.PostAsJsonAsync("/posts",
            new { userId, title, body }, cancellationToken);
        response.EnsureSuccessStatusCode();
        var result = await response.Content.ReadAsStringAsync(cancellationToken);
        return result;
    }
}

